# Prompt: Using Python: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

class PaymentProcessingError(Exception):
    pass


class InvalidRoleError(PaymentProcessingError):
    pass


class InvalidCartError(PaymentProcessingError):
    pass


class PaymentFailedError(PaymentProcessingError):
    pass


DISCOUNT_RATES = {
    "enterprise": 0.30,
    "premium": 0.15,
    "basic": 0.00,
}


def validate_user_role(user):
    if not user or not isinstance(user, dict):
        raise InvalidRoleError("Invalid user object provided.")
    role = user.get("role")
    if not role:
        raise InvalidRoleError("User has no role defined.")
    role = role.lower().strip()
    if role not in DISCOUNT_RATES:
        raise InvalidRoleError(
            f"Invalid user role: '{role}'. Must be one of: {list(DISCOUNT_RATES.keys())}"
        )
    return role


def get_discount_percentage(role):
    return DISCOUNT_RATES.get(role, 0.00)


def calculate_cart_total(cart_items):
    if not cart_items or not isinstance(cart_items, list):
        raise InvalidCartError("Cart items must be a non-empty list.")

    total = 0.0
    for idx, item in enumerate(cart_items):
        if not isinstance(item, dict):
            raise InvalidCartError(f"Cart item at index {idx} is not a valid dictionary.")
        name = item.get("name", f"item_{idx}")
        price = item.get("price")
        quantity = item.get("quantity", 1)

        if price is None:
            raise InvalidCartError(f"Cart item '{name}' is missing a price.")
        if not isinstance(price, (int, float)) or price < 0:
            raise InvalidCartError(f"Cart item '{name}' has an invalid price: {price}")
        if not isinstance(quantity, int) or quantity < 1:
            raise InvalidCartError(f"Cart item '{name}' has an invalid quantity: {quantity}")

        total += price * quantity

    return round(total, 2)


def apply_discount(total, discount_percentage):
    discount_amount = round(total * discount_percentage, 2)
    discounted_total = round(total - discount_amount, 2)
    return discounted_total, discount_amount


def validate_payment_details(payment_details):
    if not payment_details or not isinstance(payment_details, dict):
        raise PaymentFailedError("Invalid payment details provided.")

    required_fields = ["method", "card_number"]
    for field in required_fields:
        if field not in payment_details or not payment_details[field]:
            raise PaymentFailedError(f"Missing required payment field: '{field}'")

    method = payment_details["method"].lower().strip()
    valid_methods = ["credit_card", "debit_card", "paypal", "bank_transfer"]
    if method not in valid_methods:
        raise PaymentFailedError(
            f"Invalid payment method: '{method}'. Must be one of: {valid_methods}"
        )

    card_number = str(payment_details["card_number"]).replace(" ", "").replace("-", "")
    if not card_number.isdigit() or len(card_number) < 13 or len(card_number) > 19:
        raise PaymentFailedError("Invalid card number provided.")

    return True


def execute_payment(amount, payment_details):
    validate_payment_details(payment_details)

    if amount <= 0:
        raise PaymentFailedError("Payment amount must be greater than zero.")

    # Simulate payment processing
    transaction_id = f"TXN-{hash(frozenset(payment_details.items())) % 1000000:06d}"

    return {
        "success": True,
        "transaction_id": transaction_id,
        "amount_charged": amount,
        "payment_method": payment_details["method"],
    }


def process_payment(user, cart_items, payment_details):
    # Step 1: Validate user role
    role = validate_user_role(user)

    # Step 2: Calculate discount percentage based on role
    discount_percentage = get_discount_percentage(role)

    # Step 3: Calculate cart total
    cart_total = calculate_cart_total(cart_items)

    # Step 4: Apply discount to cart total
    final_total, discount_amount = apply_discount(cart_total, discount_percentage)

    # Step 5: Process the payment
    payment_result = execute_payment(final_total, payment_details)

    # Build and return the receipt
    receipt = {
        "user": user.get("name", "Unknown"),
        "role": role,
        "cart_items": cart_items,
        "cart_total": cart_total,
        "discount_percentage": f"{int(discount_percentage * 100)}%",
        "discount_amount": discount_amount,
        "final_total": final_total,
        "payment": payment_result,
    }

    return receipt


if __name__ == "__main__":
    # Example usage
    enterprise_user = {"name": "Alice", "role": "enterprise", "email": "alice@corp.com"}
    premium_user = {"name": "Bob", "role": "premium", "email": "bob@example.com"}
    basic_user = {"name": "Charlie", "role": "basic", "email": "charlie@mail.com"}

    cart = [
        {"name": "Laptop", "price": 999.99, "quantity": 1},
        {"name": "Mouse", "price": 29.99, "quantity": 2},
        {"name": "Keyboard", "price": 79.99, "quantity": 1},
    ]

    payment_info = {
        "method": "credit_card",
        "card_number": "4111111111111111",
        "expiry": "12/25",
        "cvv": "123",
    }

    for user in [enterprise_user, premium_user, basic_user]:
        try:
            result = process_payment(user, cart, payment_info)
            print(f"\n--- Receipt for {result['user']} ({result['role']}) ---")
            print(f"  Cart Total:    ${result['cart_total']:.2f}")
            print(f"  Discount:      {result['discount_percentage']} (-${result['discount_amount']:.2f})")
            print(f"  Final Total:   ${result['final_total']:.2f}")
            print(f"  Transaction:   {result['payment']['transaction_id']}")
            print(f"  Status:        {'SUCCESS' if result['payment']['success'] else 'FAILED'}")
        except PaymentProcessingError as e:
            print(f"\nPayment error for {user.get('name', 'Unknown')}: {e}")